import{c as e,Q as o,j as d,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"A Good AGENTS.md Is a Model Upgrade. A Bad One Is Worse Than No Docs at All","description":"","frontmatter":{"url":"https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files","title":"A Good AGENTS.md Is a Model Upgrade. A Bad One Is Worse Than No Docs at All","date":"2026-05-02T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-02-augmentcode-how-to-write-good-agents-md.md","filePath":"research/ai-articles/scored/2026-05-02-augmentcode-how-to-write-good-agents-md.md","lastUpdated":1779894392000}'),a={name:"research/ai-articles/scored/2026-05-02-augmentcode-how-to-write-good-agents-md.md"};function s(n,t,l,i,c,h){return o(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="a-good-agents-md-is-a-model-upgrade-a-bad-one-is-worse-than-no-docs-at-all" tabindex="-1">A Good AGENTS.md Is a Model Upgrade. A Bad One Is Worse Than No Docs at All <a class="header-anchor" href="#a-good-agents-md-is-a-model-upgrade-a-bad-one-is-worse-than-no-docs-at-all" aria-label="Permalink to &quot;A Good AGENTS.md Is a Model Upgrade. A Bad One Is Worse Than No Docs at All&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files" target="_blank" rel="noreferrer">https://www.augmentcode.com/blog/how-to-write-good-agents-dot-md-files</a><br><strong>作者</strong>：Augment Code（官方部落格）<br><strong>發佈日期</strong>：2026 年（確切日期未標示）<br><strong>收錄日期</strong>：2026-05-02<br><strong>類型</strong>：原廠研究報告（vendor content，含 internal eval 數據）</p><hr><h2 id="文章背景" tabindex="-1">文章背景 <a class="header-anchor" href="#文章背景" aria-label="Permalink to &quot;文章背景&quot;">​</a></h2><p>Augment Code 是一家專注於讓 AI 更理解大型企業 codebase 的 AI coding assistant 公司。本文為其系統性 eval 研究，測量 <code>AGENTS.md</code>（或 <code>CLAUDE.md</code> 等等效文件）對 code generation 品質的影響，並量化哪些文件模式有效、哪些有害。</p><hr><h2 id="核心發現" tabindex="-1">核心發現 <a class="header-anchor" href="#核心發現" aria-label="Permalink to &quot;核心發現&quot;">​</a></h2><h3 id="結論一-文件品質-≈-模型升級效果" tabindex="-1">結論一：文件品質 ≈ 模型升級效果 <a class="header-anchor" href="#結論一-文件品質-≈-模型升級效果" aria-label="Permalink to &quot;結論一：文件品質 ≈ 模型升級效果&quot;">​</a></h3><ul><li>最佳 <code>AGENTS.md</code> 帶來的性能提升，<strong>相當於跨越一個 Claude 模型等級</strong>（如 Haiku → Sonnet）。</li><li>最差 <code>AGENTS.md</code> 比完全沒有文件還糟，最差情況讓 completeness <strong>下降 30%</strong>。</li></ul><h3 id="結論二-7-個有效文件模式" tabindex="-1">結論二：7 個有效文件模式 <a class="header-anchor" href="#結論二-7-個有效文件模式" aria-label="Permalink to &quot;結論二：7 個有效文件模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>效果</th><th>說明</th></tr></thead><tbody><tr><td><strong>Progressive Disclosure</strong></td><td>10–15% 提升</td><td>主文件 100–150 行，細節用 reference 文件</td></tr><tr><td><strong>Procedural Workflows</strong></td><td>遺漏檔案 40%→10%，correctness +25%，completeness +20%</td><td>六步驟部署流程範例</td></tr><tr><td><strong>Decision Tables</strong></td><td>best practices +25%</td><td>結構化決策矩陣（如 React Query vs Zustand 選擇標準）</td></tr><tr><td><strong>Production Code Examples</strong></td><td>程式碼重用 +20%，pattern 一致性提升</td><td>真實 codebase 的 3–10 行片段</td></tr><tr><td><strong>Domain-Specific Rules</strong></td><td>有效，但規則過多效果遞減</td><td>語言或組織特定限制，需具體可執行</td></tr><tr><td><strong>Prohibition + Solution</strong></td><td>防止探索失敗</td><td>&quot;Don&#39;t&quot; 必須搭配對應的 &quot;Do&quot;，否則觸發驗證循環</td></tr><tr><td><strong>Modular Architecture</strong></td><td>優於 repo-root 一份大文件</td><td>模組層級文件優先</td></tr></tbody></table><h3 id="結論三-2-個主要失敗模式" tabindex="-1">結論三：2 個主要失敗模式 <a class="header-anchor" href="#結論三-2-個主要失敗模式" aria-label="Permalink to &quot;結論三：2 個主要失敗模式&quot;">​</a></h3><p><strong>1. Overexploration Trap（過度探索陷阱）</strong></p><ul><li>過長的架構概述 → agent 載入 80K+ 無關 token</li><li>30+ 條 &quot;don&#39;t&quot; 規則但無替代方案 → 觸發驗證循環</li><li>結果：執行時間加倍，completeness 下降 20%</li></ul><p><strong>2. Incompatible New Patterns（舊文件誤導新架構）</strong></p><ul><li>文件描述現有做法，但任務是新架構設計時會誤導 agent</li><li>解法是 specification-driven development，而非更多文件</li></ul><hr><h2 id="文件可發現性-discovery-rate" tabindex="-1">文件可發現性（Discovery Rate） <a class="header-anchor" href="#文件可發現性-discovery-rate" aria-label="Permalink to &quot;文件可發現性（Discovery Rate）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>位置</th><th>發現率</th></tr></thead><tbody><tr><td><code>AGENTS.md</code>（repo root）</td><td>100%</td></tr><tr><td>被明確 reference 的文件</td><td>90%+</td></tr><tr><td>工作目錄的 <code>README.md</code></td><td>80%+</td></tr><tr><td>子目錄 <code>README</code></td><td>~40%</td></tr><tr><td><code>_docs/</code> 等孤立資料夾</td><td>&lt;10%</td></tr></tbody></table><blockquote><p>Agent 的文件發現機制：約 50% 透過 grep 和語意搜尋，不只依靠明確 reference。</p></blockquote><hr><h2 id="各目標對應的最佳模式" tabindex="-1">各目標對應的最佳模式 <a class="header-anchor" href="#各目標對應的最佳模式" aria-label="Permalink to &quot;各目標對應的最佳模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目標</th><th>推薦模式</th></tr></thead><tbody><tr><td>程式碼重用</td><td>Production code examples</td></tr><tr><td>Best practices</td><td>Decision tables</td></tr><tr><td>Feature completeness</td><td>Procedural workflows</td></tr><tr><td>Gotcha handling</td><td>Paired &quot;don&#39;t/do&quot; statements</td></tr><tr><td>Context 效率</td><td>Progressive disclosure</td></tr></tbody></table><hr><h2 id="遷移建議" tabindex="-1">遷移建議 <a class="header-anchor" href="#遷移建議" aria-label="Permalink to &quot;遷移建議&quot;">​</a></h2><ul><li>現有 <code>README.md</code> 可複用，但需激進刪減</li><li>品質高且最新的文件從模組層級 <code>AGENTS.md</code> reference</li><li>每份文件 reference 上限：10–15 個</li><li>審視周圍文件環境：龐大 spec 文件（500K+ 字元）會污染精心寫的 <code>AGENTS.md</code></li></ul><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接量化本 workspace CLAUDE.md 設計原則（Progressive Disclosure、Prohibition+Solution 等），多項已實作，可立即用來稽核現有 rules</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>「壞文件比沒文件還糟 -30%」、「overexploration trap」是新量化洞見；其餘模式與既有最佳實踐重疊</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>有具體 eval 數字，但為自家 internal eval，未外部驗證；vendor content 偏差存在</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>有具體失敗模式、discovery rate 表、metric-specific 優化表——可操作性高</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>直接適用於所有 <code>CLAUDE.md</code> / <code>AGENTS.md</code> 設計場景，跨工具通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.0/10</strong></td><td>9×0.3 + 7×0.2 + 7×0.2 + 8×0.15 + 9×0.15 = 2.7 + 1.4 + 1.4 + 1.2 + 1.35 = <strong>8.05 ≈ 8.0</strong></td></tr></tbody></table><p><strong>整合決策</strong>：Rule（強化既有規則）<br><strong>整合位置</strong>：<code>.claude/rules/skill-authoring.md</code> — 以 Overexploration Trap 和 Prohibition+Solution 模式補充 §4「規則寫法」和 §2「SKILL.md 長度控制」<br><strong>整合狀態</strong>：待實作</p>',30)])])}const m=e(a,[["render",s]]);export{u as __pageData,m as default};
